# filename: calculator.py
"""
命令行计算器

支持加减乘除运算，支持连续计算与退出指令。
"""

import re
import operator
import sys

# 支持的运算符及对应函数
OPS = {
    '+': operator.add,
    '-': operator.sub,
    '*': operator.mul,
    '/': operator.truediv,
}

def parse_input(raw: str):
    """
    解析用户输入，返回 (num1, op, num2) 或 None。
    支持整数与小数。
    """
    raw = raw.strip()
    # 匹配 <number> <op> <number>，支持正负数与小数
    pattern = r'^\s*([+-]?\d+(?:\.\d+)?)\s*([+\-*/])\s*([+-]?\d+(?:\.\d+)?)\s*$'
    match = re.fullmatch(pattern, raw)
    if not match:
        return None
    num1, op, num2 = match.groups()
    try:
        num1 = float(num1)
        num2 = float(num2)
    except ValueError:
        return None
    return num1, op, num2

def safe_divide(a, b):
    """安全除法，除零返回错误信息。"""
    if b == 0:
        raise ZeroDivisionError("除数不能为 0")
    return OPS['/'](a, b)

def calculate(expr: str):
    """
    计算表达式，返回结果或错误信息字符串。
    """
    parsed = parse_input(expr)
    if parsed is None:
        return "输入格式错误！请输入形如：3 + 4 或 5.2 * -3 的表达式。"
    num1, op, num2 = parsed
    try:
        if op == '/':
            result = safe_divide(num1, num2)
        else:
            result = OPS[op](num1, num2)
    except ZeroDivisionError as e:
        return str(e)
    # 若结果为整数，则转为 int 显示
    if result.is_integer():
        result = int(result)
    return result

def repl():
    """交互式命令行循环。"""
    print("=== 命令行计算器 ===")
    print("输入表达式进行计算，例如：3 + 4 或 5.2 * -3")
    print("输入 q 或 quit 退出程序")
    while True:
        try:
            user_input = input(">>> ").strip()
        except (KeyboardInterrupt, EOFError):
            print("\n再见！")
            break
        if user_input.lower() in {'q', 'quit', 'exit'}:
            print("再见！")
            break
        if not user_input:
            continue
        output = calculate(user_input)
        print(output)

if __name__ == '__main__':
    repl()

#!/usr/bin/env python3
# usage: python calc.py -e "3 + 4 * 2"   或   python calc.py （进入 REPL）

import argparse
import re
import sys
from enum import Enum, auto
from typing import List, NamedTuple, Tuple


class TokenType(Enum):
    NUMBER = auto()
    PLUS = auto()
    MINUS = auto()
    MUL = auto()
    DIV = auto()
    LPAREN = auto()
    RPAREN = auto()


class Token(NamedTuple):
    type: TokenType
    value: str | float


class ParseError(Exception):
    """基类：词法/语法异常统一基类，便于 ErrorReporter 捕获"""
    pass


class LexError(ParseError):
    """词法错误：非法字符"""
    pass


class SyntaxError(ParseError):
    """语法错误：括号不匹配、空表达式等"""
    pass


class DivideByZeroError(ArithmeticError):
    """运行时除零"""
    pass


class OverflowError(ArithmeticError):
    """结果溢出（绝对值 > 1e308）"""
    pass


# ---------- Tokenizer ----------
TOKEN_SPEC = [
    ("NUMBER",  r"\d+(?:\.\d+)?"),   # 整数或浮点
    ("PLUS",    r"\+"),
    ("MINUS",   r"-"),
    ("MUL",     r"\*"),
    ("DIV",     r"/"),
    ("LPAREN",  r"\("),
    ("RPAREN",  r"\)"),
    ("SKIP",    r"\s+"),            # 空白
    ("MISMATCH", r"."),             # 任何其他字符
]
MASTER_RE = re.compile("|".join(f"(?P<{name}>{pattern})" for name, pattern in TOKEN_SPEC))


def tokenize(expr: str) -> List[Token]:
    """将表达式转为 Token 列表，遇非法字符抛 LexError"""
    tokens: List[Token] = []
    for mo in MASTER_RE.finditer(expr):
        kind = mo.lastgroup
        lexeme = mo.group()
        if kind == "NUMBER":
            tokens.append(Token(TokenType.NUMBER, float(lexeme)))
        elif kind == "PLUS":
            tokens.append(Token(TokenType.PLUS, lexeme))
        elif kind == "MINUS":
            tokens.append(Token(TokenType.MINUS, lexeme))
        elif kind == "MUL":
            tokens.append(Token(TokenType.MUL, lexeme))
        elif kind == "DIV":
            tokens.append(Token(TokenType.DIV, lexeme))
        elif kind == "LPAREN":
            tokens.append(Token(TokenType.LPAREN, lexeme))
        elif kind == "RPAREN":
            tokens.append(Token(TokenType.RPAREN, lexeme))
        elif kind == "SKIP":
            continue
        else:  # MISMATCH
            raise LexError(f"非法字符 '{lexeme}'")
    return tokens


# ---------- Parser（调度场算法） ----------
PRECEDENCE = {
    TokenType.PLUS: 1,
    TokenType.MINUS: 1,
    TokenType.MUL: 2,
    TokenType.DIV: 2,
}


def infix_to_rpn(tokens: List[Token]) -> List[Token]:
    """中缀 Token → 后缀 RPN，检测括号不匹配"""
    output: List[Token] = []
    stack: List[Token] = []

    for tok in tokens:
        if tok.type == TokenType.NUMBER:
            output.append(tok)
        elif tok.type in (TokenType.PLUS, TokenType.MINUS, TokenType.MUL, TokenType.DIV):
            while stack and stack[-1].type != TokenType.LPAREN and \
                  PRECEDENCE[stack[-1].type] >= PRECEDENCE[tok.type]:
                output.append(stack.pop())
            stack.append(tok)
        elif tok.type == TokenType.LPAREN:
            stack.append(tok)
        elif tok.type == TokenType.RPAREN:
            while stack and stack[-1].type != TokenType.LPAREN:
                output.append(stack.pop())
            if not stack:
                raise SyntaxError("括号不匹配：缺少左括号")
            stack.pop()  # 弹出 '('
        else:
            raise SyntaxError(f"未知 Token 类型 {tok.type}")

    while stack:
        top = stack.pop()
        if top.type == TokenType.LPAREN:
            raise SyntaxError("括号不匹配：缺少右括号")
        output.append(top)
    return output


# ---------- Evaluator ----------
def eval_rpn(rpn: List[Token]) -> float:
    """对 RPN 求值，返回浮点结果，处理除零/溢出"""
    stack: List[float] = []
    for tok in rpn:
        if tok.type == TokenType.NUMBER:
            stack.append(tok.value)
        else:
            if len(stack) < 2:
                raise SyntaxError("运算符缺少操作数")
            b = stack.pop()
            a = stack.pop()
            if tok.type == TokenType.PLUS:
                res = a + b
            elif tok.type == TokenType.MINUS:
                res = a - b
            elif tok.type == TokenType.MUL:
                res = a * b
            elif tok.type == TokenType.DIV:
                if b == 0.0:
                    raise DivideByZeroError("除零错误")
                res = a / b
            else:
                raise SyntaxError(f"未知运算符 {tok.value}")
            if abs(res) > 1e308:
                raise OverflowError("结果溢出")
            stack.append(res)
    if len(stack) != 1:
        raise SyntaxError("表达式无效")
    return stack[0]


# ---------- ErrorReporter ----------
def report(err: Exception) -> Tuple[int, str]:
    """统一异常 → (exit_code, friendly_msg)"""
    if isinstance(err, LexError):
        return 2, f"词法错误：{err}"
    if isinstance(err, SyntaxError):
        return 3, f"语法错误：{err}"
    if isinstance(err, DivideByZeroError):
        return 4, f"运行错误：{err}"
    if isinstance(err, OverflowError):
        return 5, f"运行错误：{err}"
    # 其他异常
    return 6, f"未知错误：{err}"


# ---------- CLI ----------
def evaluate(expr: str) -> float:
    """端到端计算，抛出自定义异常"""
    if not expr.strip():
        raise SyntaxError("空表达式")
    tokens = tokenize(expr)
    rpn = infix_to_rpn(tokens)
    return eval_rpn(rpn)


def repl() -> None:
    """交互式 REPL，支持 quit/exit 退出"""
    print("Calc REPL — 输入表达式或 exit/quit 离开")
    try:
        import readline  # 可选，提升体验
    except ImportError:
        pass
    while True:
        try:
            line = input(">>> ").strip()
        except (EOFError, KeyboardInterrupt):
            print("\n再见！")
            break
        if line.lower() in {"exit", "quit"}:
            print("再见！")
            break
        if not line:
            continue
        try:
            result = evaluate(line)
            print(result)
        except Exception as e:
            _, msg = report(e)
            print(msg, file=sys.stderr)


def main(argv: List[str]) -> int:
    parser = argparse.ArgumentParser(prog="calc", description="命令行四则运算器")
    parser.add_argument("-e", "--expr", help="一次性计算表达式")
    args = parser.parse_args(argv[1:])
    if args.expr:
        try:
            print(evaluate(args.expr))
            return 0
        except Exception as e:
            code, msg = report(e)
            print(msg, file=sys.stderr)
            return code
    else:
        repl()
        return 0


if __name__ == "__main__":
    sys.exit(main(sys.argv))

import unittest
from calc import (
    tokenize, infix_to_rpn, eval_rpn,
    LexError, SyntaxError, DivideByZeroError, OverflowError
)


class TestTokenizer(unittest.TestCase):
    def test_basic(self):
        self.assertEqual([t.value for t in tokenize("3+4*2")], [3.0, "+", "*", 2.0])

    def test_float(self):
        self.assertEqual([t.value for t in tokenize("1.5 / 0.5")], [1.5, "/", 0.5])

    def test_paren(self):
        self.assertEqual([t.type for t in tokenize("(1+2)")],
                         ["LPAREN", "NUMBER", "PLUS", "NUMBER", "RPAREN"])

    def test_invalid(self):
        with self.assertRaises(LexError):
            tokenize("3 @ 4")


class TestParser(unittest.TestCase):
    def test_simple(self):
        tokens = tokenize("3 + 4 * 2")
        rpn = infix_to_rpn(tokens)
        self.assertEqual([t.value for t in rpn], [3.0, 4.0, 2.0, "*", "+"])

    def test_paren(self):
        tokens = tokenize("(3 + 4) * 2")
        rpn = infix_to_rpn(tokens)
        self.assertEqual([t.value for t in rpn], [3.0, 4.0, "+", 2.0, "*"])

    def test_mismatch_left(self):
        with self.assertRaises(SyntaxError):
            infix_to_rpn(tokenize("3 + 4 )"))

    def test_mismatch_right(self):
        with self.assertRaises(SyntaxError):
            infix_to_rpn(tokenize("( 3 + 4"))


class TestEvaluator(unittest.TestCase):
    def test_add(self):
        self.assertEqual(eval_rpn(infix_to_rpn(tokenize("3 + 4"))), 7.0)

    def test_sub(self):
        self.assertEqual(eval_rpn(infix_to_rpn(tokenize("10 - 2"))), 8.0)

    def test_mul_div(self):
        self.assertEqual(eval_rpn(infix_to_rpn(tokenize("3 + 4 * 2 / 1"))), 11.0)

    def test_div_zero(self):
        with self.assertRaises(DivideByZeroError):
            eval_rpn(infix_to_rpn(tokenize("5 / 0")))

    def test_overflow(self):
        with self.assertRaises(OverflowError):
            eval_rpn([tokenize("1e308 * 10")[0]])  # 手动构造 RPN


if __name__ == "__main__":
    unittest.main()

