import unittest
from calc import Tokenizer, Parser, ParseError, TokenType

class TestParser(unittest.TestCase):
    def setUp(self):
        self.tok = Tokenizer()
        self.parser = Parser()

    def tokens_values(self, expr):
        return [t.value for t in self.parser.infix_to_rpn(self.tok.tokenize(expr))]

    def test_single_number(self):
        self.assertEqual(self.tokens_values('42'), [42.0])

    def test_simple_add(self):
        self.assertEqual(self.tokens_values('3+4'), [3.0, 4.0, '+'])

    def test_priority_mul_over_add(self):
        self.assertEqual(self.tokens_values('3+4*2'), [3.0, 4.0, 2.0, '*', '+'])

    def test_left_associative(self):
        # 3 - 2 - 1 应为 (3-2)-1
        self.assertEqual(self.tokens_values('3-2-1'), [3.0, 2.0, '-', 1.0, '-'])

    def test_parentheses(self):
        self.assertEqual(self.tokens_values('(3+4)*2'), [3.0, 4.0, '+', 2.0, '*'])

    def test_nested_parens(self):
        self.assertEqual(self.tokens_values('((2+3))'), [2.0, 3.0, '+'])

    def test_missing_rparen(self):
        with self.assertRaises(ParseError):
            self.parser.infix_to_rpn(self.tok.tokenize('(3+4'))

    def test_extra_rparen(self):
        with self.assertRaises(ParseError):
            self.parser.infix_to_rpn(self.tok.tokenize('3+4)'))

    def test_empty_tokens(self):
        self.assertEqual(self.parser.infix_to_rpn([]), [])

if __name__ == '__main__':
    unittest.main()

import unittest
from calc import Tokenizer, Parser, Evaluator, DivideByZeroError, EvalError, Token, TokenType

class TestEvaluator(unittest.TestCase):
    def setUp(self):
        self.e = Evaluator()
        self.tok = Tokenizer()
        self.p = Parser()

    def eval_expr(self, expr):
        rpn = self.p.infix_to_rpn(self.tok.tokenize(expr))
        return self.e.eval_rpn(rpn)

    def test_single_number(self):
        self.assertEqual(self.eval_expr('9'), 9.0)

    def test_add(self):
        self.assertEqual(self.eval_expr('3+4'), 7.0)

    def test_sub_negative_result(self):
        self.assertEqual(self.eval_expr('3-7'), -4.0)

    def test_mul(self):
        self.assertEqual(self.eval_expr('3*4'), 12.0)

    def test_div_float(self):
        self.assertEqual(self.eval_expr('10/4'), 2.5)

    def test_div_zero(self):
        with self.assertRaises(DivideByZeroError):
            self.eval_expr('5/0')

    def test_complex(self):
        self.assertEqual(self.eval_expr('(3+4)*2-10/5'), 12.0)

    def test_operand_shortage(self):
        rpn = [Token(TokenType.OP, '+')]
        with self.assertRaises(EvalError):
            self.e.eval_rpn(rpn)

    def test_too_many_operands(self):
        rpn = [Token(TokenType.NUM, 1), Token(TokenType.NUM, 2), Token(TokenType.NUM, 3)]
        with self.assertRaises(EvalError):
            self.e.eval_rpn(rpn)

if __name__ == '__main__':
    unittest.main()

import unittest
from calc import CLI

class TestCLIEvaluate(unittest.TestCase):
