        self.cli = CLI()

    def test_ok(self):
        self.assertEqual(self.cli.evaluate('3+4'), 7.0)

    def test_negative(self):
        res = self.cli.evaluate('2 - 10')
        self.assertEqual(res, -8.0)

    def test_div_zero(self):
        code, msg = self.cli.evaluate('3/0')
        self.assertEqual(code, 3)
        self.assertIn('除零', msg)

    def test_lex_error(self):
        code, msg = self.cli.evaluate('3$4')
        self.assertEqual(code, 1)

    def test_parse_error(self):
        code, msg = self.cli.evaluate('3+4)')
        self.assertEqual(code, 2)

    def test_empty(self):
        # 空表达式返回空 rpn → EvalError 多余操作数
        code, msg = self.cli.evaluate('')
        self.assertEqual(code, 4)

    def test_big_number(self):
        res = self.cli.evaluate('999999999999*0')
        self.assertEqual(res, 0.0)

