# filename: todo.py
"""
极简命令行 TODO 列表应用
功能：add / done / delete / list / exit
数据持久化：todo.json（与脚本同目录）
错误处理：文件损坏、命令格式错误、输入越界等均有提示
"""

import json
import os
import sys
from typing import List, Dict

JSON_FILE = "todo.json"


# ---------- 数据层 ----------
def load_todos() -> List[Dict[str, bool]]:
    """加载 JSON，若文件不存在或损坏则返回空列表。"""
    if not os.path.exists(JSON_FILE):
        return []
    try:
        with open(JSON_FILE, "r", encoding="utf-8") as f:
            data = json.load(f)
            if isinstance(data, list):
                return data
    except (json.JSONDecodeError, OSError):
        print("⚠️  数据文件损坏，已重置为空列表。")
    return []


def save_todos(todos: List[Dict[str, bool]]) -> None:
    """保存到 JSON，失败时给出提示。"""
    try:
        with open(JSON_FILE, "w", encoding="utf-8") as f:
            json.dump(todos, f, ensure_ascii=False, indent=2)
    except OSError as e:
        print(f"❌ 保存失败：{e}")


# ---------- 业务层 ----------
def add_todo(todos: List[Dict[str, bool]], title: str) -> None:
    todos.append({"title": title, "done": False})
    print(f"✅ 已添加：{title}")


def list_todos(todos: List[Dict[str, bool]]) -> None:
    if not todos:
        print("📭 暂无待办事项。")
        return
    for idx, item in enumerate(todos, 1):
        mark = "✔️" if item["done"] else "⬜"
        print(f"{idx}. {mark} {item['title']}")


def mark_done(todos: List[Dict[str, bool]], index: int) -> None:
    if 1 <= index <= len(todos):
        todos[index - 1]["done"] = True
        print(f"✔️  已完成：{todos[index - 1]['title']}")
    else:
        print("❌ 序号超出范围。")


def delete_todo(todos: List[Dict[str, bool]], index: int) -> None:
    if 1 <= index <= len(todos):
        removed = todos.pop(index - 1)
        print(f"🗑️  已删除：{removed['title']}")
    else:
        print("❌ 序号超出范围。")


# ---------- 交互层 ----------
def print_help() -> None:
    print(
        """
帮助：
  add  <标题>     添加新待办
  done <序号>     标记已完成
  del  <序号>     删除待办
  list            列出所有待办
  help            显示本帮助
  exit            退出程序
"""
    )


def main() -> None:
    todos = load_todos()
    print("🚀 欢迎使用极简 TODO 列表")
    print_help()

    while True:
        try:
            cmd = input("\n>>> ").strip()
        except (KeyboardInterrupt, EOFError):
            print("\n👋 再见！")
            sys.exit(0)

        if not cmd:
            continue

        parts = cmd.split(maxsplit=1)
        action = parts[0].lower()

        if action == "exit":
            save_todos(todos)
            print("👋 已保存，再见！")
            break

        elif action == "help":
            print_help()

        elif action == "list":
            list_todos(todos)

        elif action == "add":
            if len(parts) < 2 or not parts[1].strip():
                print("❌ 用法：add <标题>")
            else:
                add_todo(todos, parts[1].strip())

        elif action in ("done", "del", "delete"):
            if len(parts) < 2:
                print(f"❌ 用法：{action} <序号>")
                continue
            try:
                idx = int(parts[1])
            except ValueError:
                print("❌ 序号必须是数字。")
                continue
            if action == "done":
                mark_done(todos, idx)
            else:
                delete_todo(todos, idx)

        else:
            print("❌ 未知命令，输入 help 查看帮助。")

        # 每次操作后自动保存
        save_todos(todos)


if __name__ == "__main__":
    main()

from __future__ import annotations
import uuid
from dataclasses import dataclass, field
from datetime import datetime
from enum import Enum


class Priority(Enum):
    low = "low"
    medium = "medium"
    high = "high"


class Status(Enum):
    pending = "pending"
    completed = "completed"


@dataclass(slots=True)
class Task:
    id: str = field(default_factory=lambda: str(uuid.uuid4()))
    title: str
    description: str = ""
    status: Status = Status.pending
    priority: Priority = Priority.medium
    created_at: datetime = field(default_factory=datetime.utcnow)

    # 自定义初始化（避免 dataclass 处理默认值的陷阱）
    def __post_init__(self):
        if not isinstance(self.status, Status):
            self.status = Status(self.status)
        if not isinstance(self.priority, Priority):
            self.priority = Priority(self.priority)
        if isinstance(self.created_at, str):
            self.created_at = datetime.fromisoformat(self.created_at)

    def to_dict(self) -> dict:
        return {
            "id": self.id,
            "title": self.title,
            "description": self.description,
            "status": self.status.value,
            "priority": self.priority.value,
            "created_at": self.created_at.isoformat(timespec="seconds"),
        }

    @classmethod
    def from_dict(cls, data: dict) -> Task:
        return cls(**data)

from typing import List, Optional

from models import Task, Status, Priority
from repository import JsonTaskRepository


class TaskService:
    def __init__(self, repo: JsonTaskRepository):
        self._repo = repo

    def create_task(self, title: str, description: str, priority: Priority) -> Task:
        if not title.strip():
            raise ValueError("Title cannot be empty.")
        task = Task(title=title.strip(), description=description.strip(), priority=priority)
        tasks = self._repo.load()
        tasks.append(task)
        self._repo.save(tasks)
        return task

    def remove_task(self, task_id: str) -> bool:
        tasks = self._repo.load()
        for idx, t in enumerate(tasks):
            if t.id == task_id:
                del tasks[idx]
                self._repo.save(tasks)
                return True
        return False

    def mark_done(self, task_id: str) -> bool:
        tasks = self._repo.load()
        for t in tasks:
            if t.id == task_id:
                if t.status is Status.completed:
                    return True
                t.status = Status.completed
                self._repo.save(tasks)
                return True
        return False

    def query_tasks(
        self,
        status: Optional[Status] = None,
        keyword: Optional[str] = None,
        priority: Optional[Priority] = None,
    ) -> List[Task]:
        tasks = self._repo.load()
        if status is not None:
            tasks = [t for t in tasks if t.status == status]
        if priority is not None:
            tasks = [t for t in tasks if t.priority == priority]
        if keyword:
            kw = keyword.lower()
            tasks = [
                t
                for t in tasks
                if kw in t.title.lower() or kw in t.description.lower()
            ]
        return tasks

import shutil
from pathlib import Path

import json


class FileIntegrityGuard:
    def __init__(self, file_path: Path, bak_suffix: str = ".bak"):
        self._file: Path = file_path
        self._bak: Path = file_path.with_suffix(file_path.suffix + bak_suffix)

    def verify_or_restore(self) -> bool:
        """返回 True 表示可用（原文件或已恢复）"""
        if self._file.exists():
            try:
                with self._file.open("r", encoding="utf-8") as f:
                    json.load(f)
                # 健康文件，顺便更新备份
                shutil.copy2(self._file, self._bak)
                return True
            except (json.JSONDecodeError, OSError):
                # 损坏，尝试回滚
                if self._bak.exists():
                    shutil.copy2(self._bak, self._file)
                    return True
                # 无备份，创建空数组
                self._file.write_text("[]", encoding="utf-8")
                return True
        else:
            # 首次使用
            if self._bak.exists():
                shutil.copy2(self._bak, self._file)
            else:
                self._file.write_text("[]", encoding="utf-8")
            return True

