class ExceptionHandlerMiddleware(BaseHTTPMiddleware):
    """统一错误响应"""
    async def dispatch(self, request: Request, call_next):
        trace_id = str(uuid4())
        try:
            response = await call_next(request)
            return response
        except BusinessError as exc:
            return JSONResponse(
                status_code=exc.status_code,
                content={
                    "code": exc.code,
                    "msg": exc.message,
                    "detail": exc.detail,
                    "trace_id": trace_id,
                },
            )
        except JWTError as exc:
            return JSONResponse(
                status_code=exc.status_code,
                content={
                    "code": exc.code,
                    "msg": exc.message,
                    "detail": exc.detail,
                    "trace_id": trace_id,
                },
            )
        except Exception as exc:
            # 兜底 500
            return JSONResponse(
                status_code=500,
                content={
                    "code": "INTERNAL_SERVER_ERROR",
                    "msg": "服务器内部错误",
                    "detail": str(exc),
                    "trace_id": trace_id,
                },
            )


@asynccontextmanager
async def lifespan(app: FastAPI):
    await create_db_and_tables()
    yield


app = FastAPI(
