import logging
import urllib.robotparser
from urllib.parse import urlparse

import aiohttp

class RobotChecker:
    def __init__(self):
        self._cache = {}  # domain -> RobotFileParser

    def can_fetch(self, url: str) -> bool:
        domain = urlparse(url).netloc.lower()
        if domain not in self._cache:
            self._cache[domain] = self._load_robots(domain)
        return self._cache[domain].can_fetch("*", url)

    def _load_robots(self, domain: str) -> urllib.robotparser.RobotFileParser:
        rp = urllib.robotparser.RobotFileParser()
        rp.set_url(f"https://{domain}/robots.txt")
        try:
            rp.read()
        except Exception as exc:
            logging.warning(f"[robots] fail to load for {domain}: {exc}")
            # 默认允许
            rp.allow_all = True
        return rp
